import{_ as i,o as e,c as a,a2 as o}from"./chunks/framework.VshInwhI.js";const p=JSON.parse('{"title":"Element Plus UI 规范","description":"","frontmatter":{},"headers":[],"relativePath":"mango-pmo/rules/frontend/02-element-plus-ui.md","filePath":"mango-pmo/rules/frontend/02-element-plus-ui.md"}'),r={name:"mango-pmo/rules/frontend/02-element-plus-ui.md"};function t(u,l,n,d,c,s){return e(),a("div",null,[...l[0]||(l[0]=[o('<h1 id="element-plus-ui-规范" tabindex="-1">Element Plus UI 规范 <a class="header-anchor" href="#element-plus-ui-规范" aria-label="Permalink to &quot;Element Plus UI 规范&quot;">​</a></h1><h2 id="_1-适用范围" tabindex="-1">1. 适用范围 <a class="header-anchor" href="#_1-适用范围" aria-label="Permalink to &quot;1. 适用范围&quot;">​</a></h2><ul><li>适用于 Mango 前端管理后台页面。</li><li>适用于基于 Mango 业务 starter 创建的业务后台页面。</li><li>默认基于 Vue 3、TypeScript 和 Element Plus。</li><li>Vue 代码、Monorepo 边界和测试要求仍以对应前端规范为准。</li></ul><h2 id="_2-需求拆解" tabindex="-1">2. 需求拆解 <a class="header-anchor" href="#_2-需求拆解" aria-label="Permalink to &quot;2. 需求拆解&quot;">​</a></h2><p>拿到页面需求后，开发前必须先提取：</p><ul><li>页面类型：列表、详情、表单、弹窗、抽屉、步骤流、看板或配置页。</li><li>查询条件：关键字、状态、类型、时间范围、所属对象、层级对象。</li><li>字典和枚举：状态、类型、来源、级别、开关、审批动作等有限选项。</li><li>辅助数据：组织、用户、角色、租户、部门、标签、分类、上级对象等关联数据。</li><li>操作集合：新增、编辑、删除、启停、导入、导出、批量操作、审批动作。</li><li>状态集合：启用、停用、草稿、发布、成功、失败、处理中、过期、异常等业务状态。</li></ul><p>拆解结果必须决定哪些内容使用已有组件，哪些内容需要新增页面私有组件，哪些内容需要下沉为公共组件。</p><h2 id="_3-选择组件" tabindex="-1">3. 选择组件 <a class="header-anchor" href="#_3-选择组件" aria-label="Permalink to &quot;3. 选择组件&quot;">​</a></h2><ul><li>字典、枚举、辅助数据和关联对象优先做成选择组件。</li><li>选择组件必须优先支持单选；业务存在批量筛选或多对象绑定时必须支持多选。</li><li>选择组件涉及远程数据时必须支持输入检索、清空、加载中、空结果和错误提示。</li><li>选择组件允许手输时，必须明确手输值的校验、保存语义和回显方式。</li><li>页面内出现两处及以上同类选择逻辑时，必须抽为组件或 composable。</li><li>公共选择组件不得直接依赖页面 store、路由、菜单或权限装配逻辑。</li><li>选择组件的 value 类型必须与后端契约一致；ID 字段按前端 ID 规则使用字符串语义。</li></ul><h2 id="_4-列表页布局" tabindex="-1">4. 列表页布局 <a class="header-anchor" href="#_4-列表页布局" aria-label="Permalink to &quot;4. 列表页布局&quot;">​</a></h2><p>列表页必须按以下顺序组织：</p><ol><li>搜索区域。</li><li>功能区域。</li><li>列表区域。</li><li>分页区域。</li><li>弹窗、抽屉或二次确认。</li></ol><p>搜索区域规则：</p><ul><li>使用 <code>ElForm</code> 承载查询条件。</li><li>查询项超过一行时必须支持展开和收起。</li><li>主按钮顺序固定为查询、重置、展开或收起。</li><li>查询按钮使用 <code>primary</code>，重置按钮使用默认按钮。</li><li>时间范围使用 <code>ElDatePicker</code> 的 range 类型，不拆成两个无关输入框。</li></ul><p>功能区域规则：</p><ul><li>位于列表上方。</li><li>左侧放主操作，例如新增、导入、导出、批量删除。</li><li>右侧放刷新、列设置、密度切换等视图操作。</li><li>主操作按钮最多一个 <code>primary</code>。</li><li>危险操作必须使用 <code>danger</code> 并带二次确认。</li></ul><p>列表区域规则：</p><ul><li>使用 <code>ElTable</code> 或项目既有表格组件。</li><li>表格列必须有稳定宽度、最小宽度或溢出策略。</li><li>ID、编码、名称、状态、时间、操作列顺序必须稳定。</li><li>操作列固定在右侧；按钮文案必须短且动作明确。</li><li>行内按钮超过三个时，低频操作必须收进 <code>ElDropdown</code>。</li></ul><p>分页区域规则：</p><ul><li>分页位于列表下方右侧。</li><li>页码、每页条数和总数必须由真实接口结果驱动。</li><li>查询条件变化后必须回到第一页。</li></ul><h2 id="_5-表单和弹窗" tabindex="-1">5. 表单和弹窗 <a class="header-anchor" href="#_5-表单和弹窗" aria-label="Permalink to &quot;5. 表单和弹窗&quot;">​</a></h2><ul><li>新增和编辑表单优先复用同一份表单组件。</li><li>表单项使用 <code>ElFormItem</code>，label 必须是业务名词，不写实现词。</li><li>必填、长度、格式、范围、唯一性等约束必须有前端校验；后端错误必须能回显到页面。</li><li>新增、修改、搜索表单必须先按业务聚集性分组，再按字段关联性排序。</li><li>同一业务对象、同一审批链路、同一金额/期限/文件信息必须放在同一组内。</li><li>级联、互相影响、前后置依赖字段必须相邻；强联动字段优先水平并列，字段较长或依赖说明较多时垂直连续。</li><li>搜索表单只保留高频条件；低频条件超过一行时必须放入展开区域。</li><li>20 个以内固定选项使用下拉选择，组件必须支持单选和多选配置。</li><li>超过 20 个选项、远程选项或增长型选项必须支持输入检索。</li><li>下拉选择必须支持清空、禁用、加载中、空结果和错误提示。</li><li>表单项顺序禁止按接口字段、数据库字段或开发便利性直接排列。</li><li>弹窗用于短表单和确认操作；抽屉用于字段多、需要上下文参照或分组编辑的场景。</li><li>保存按钮必须显示提交中状态，提交中禁止重复提交。</li><li>关闭未保存表单前必须提示用户确认。</li></ul><h2 id="_6-字体和文案层级" tabindex="-1">6. 字体和文案层级 <a class="header-anchor" href="#_6-字体和文案层级" aria-label="Permalink to &quot;6. 字体和文案层级&quot;">​</a></h2><p>页面文案必须按语义分层，不按局部视觉临时改字号：</p><ul><li>页面标题：18px，字重 600，用于页面主标题。</li><li>区块标题：16px，字重 600，用于搜索区、列表区、表单分组。</li><li>正文：14px，字重 400，用于表格、表单、普通说明。</li><li>辅助说明：13px，字重 400，用于提示、补充说明、空状态说明。</li><li>注释和次要信息：12px，字重 400，用于时间、来源、弱提示、表格补充字段。</li><li>按钮、表单控件、表格内容默认跟随 Element Plus 基础字号，不单独改小。</li></ul><p>禁止事项：</p><ul><li>禁止页面内随意使用 11px 以下字号。</li><li>禁止使用负字距。</li><li>禁止为了挤内容压缩字号；应调整布局、换行、折叠或使用提示浮层。</li><li>禁止用颜色替代文字说明表达关键状态。</li></ul><h2 id="_7-状态展示" tabindex="-1">7. 状态展示 <a class="header-anchor" href="#_7-状态展示" aria-label="Permalink to &quot;7. 状态展示&quot;">​</a></h2><ul><li>业务状态统一使用 <code>ElTag</code> 或项目公共状态标签组件。</li><li>状态颜色必须来自业务语义映射，不允许页面内手写裸色值。</li><li>成功、启用、正常类状态使用 <code>success</code>。</li><li>处理中、运行中、待审批类状态使用 <code>primary</code> 或 <code>warning</code>，按业务风险选择。</li><li>草稿、未开始、停用、关闭类状态使用 <code>info</code>。</li><li>失败、异常、拒绝、删除类状态使用 <code>danger</code>。</li><li>同一业务状态在列表、详情、表单回显中的文案和颜色必须一致。</li><li>未知状态必须显示为可识别的兜底文案，禁止空白。</li></ul><h2 id="_8-空、加载和错误状态" tabindex="-1">8. 空、加载和错误状态 <a class="header-anchor" href="#_8-空、加载和错误状态" aria-label="Permalink to &quot;8. 空、加载和错误状态&quot;">​</a></h2><ul><li>页面首次加载必须有加载状态。</li><li>列表无数据必须使用统一空状态，不显示空白表格。</li><li>查询无结果和系统无数据的空状态文案必须区分。</li><li>接口错误必须显示可理解的错误文案，并保留重试入口。</li><li>删除、禁用、批量操作等高风险动作必须显示影响范围。</li></ul><h2 id="_9-ui-质量门禁" tabindex="-1">9. UI 质量门禁 <a class="header-anchor" href="#_9-ui-质量门禁" aria-label="Permalink to &quot;9. UI 质量门禁&quot;">​</a></h2><p>页面交付前必须完成 UI 和交互走查：</p><ul><li>搜索区、功能区、列表区、分页区、弹窗或抽屉边界必须清晰，间距、对齐和密度一致。</li><li>表单字段必须按业务聚集性分组和关联性排序；联动字段必须相邻，不按接口字段顺序堆叠。</li><li>主操作、次操作、危险操作和行内操作必须位置稳定、语义清晰。</li><li>表格列宽、溢出、固定列、空状态、加载态、错误态和分页必须完整可见。</li><li>弹窗和抽屉必须有明确标题、提交中状态、重复提交保护和未保存关闭确认。</li><li>页面不得出现文字重叠、控件挤压、按钮换行失控、表格操作列遮挡或移动端/窄屏不可用。</li><li>页面必须使用真实接口、配置或可替换 provider 回显数据；禁止用静态假数据证明布局完成。</li></ul><h2 id="_10-样式边界" tabindex="-1">10. 样式边界 <a class="header-anchor" href="#_10-样式边界" aria-label="Permalink to &quot;10. 样式边界&quot;">​</a></h2><ul><li>优先使用 Element Plus 组件能力、项目设计变量和局部 class。</li><li>禁止覆盖 Element Plus 全局 class 作为页面局部方案。</li><li>禁止在页面中硬编码品牌色、状态色和大段间距常量。</li><li>新增公共样式必须说明复用场景，并放入对应公共包或主题文件。</li><li>卡片、搜索区、表格区和弹窗内部不得套多层视觉容器。</li></ul><h2 id="_11-可检查规则" tabindex="-1">11. 可检查规则 <a class="header-anchor" href="#_11-可检查规则" aria-label="Permalink to &quot;11. 可检查规则&quot;">​</a></h2><p>能用 lint、脚本或 review checklist 检查的规则必须落到检查项：</p><ul><li>检查 PMO preflight 是否加载本规范。</li><li>检查业务 starter 和 mango-cli 模板是否携带本规范。</li><li>检查页面新增选择组件时是否支持单选、多选或输入检索中的必要能力。</li><li>检查新增、修改、搜索表单是否按业务聚集性分组、关联性排序和联动相邻布局。</li><li>检查页面是否存在重复的字典、枚举、状态映射。</li><li>检查状态标签是否通过统一映射渲染，禁止页面内散写状态色。</li><li>检查列表页是否包含搜索区域、功能区域、列表区域和分页区域。</li><li>检查页面是否完成 UI 走查，并保留真实接口、截图、E2E 或手工验收证据。</li><li>检查页面是否仍存在静态假数据、硬编码字典、硬编码菜单、硬编码权限或 mock 接口依赖。</li></ul><p>当前无法稳定自动判断的视觉一致性，必须在 PR review 中按本规范人工确认。</p><h2 id="_12-禁止事项" tabindex="-1">12. 禁止事项 <a class="header-anchor" href="#_12-禁止事项" aria-label="Permalink to &quot;12. 禁止事项&quot;">​</a></h2><ul><li>禁止复制已有页面后长期保留重复选择逻辑、状态映射和表格操作布局。</li><li>禁止为单个页面创建与 Element Plus 语义冲突的控件样式。</li><li>禁止让页面私有样式成为事实全局规范。</li><li>禁止用静态选项替代必须来自接口或配置的字典、枚举和辅助数据。</li><li>禁止表单字段按接口返回顺序、数据库字段顺序或随手追加顺序布局。</li><li>禁止把“页面能打开”当作页面完成；页面必须通过真实数据、真实交互和 UI 走查验收。</li></ul>',42)])])}const m=i(r,[["render",t]]);export{p as __pageData,m as default};
